import { cacheLife, cacheTag, revalidateTag } from 'next/cache';

type Product = {
  sku: string;
  name: string;
  category: string;
  price: number;
  inventory: number;
  availability: 'In stock' | 'Low stock' | 'Backorder';
};

type CatalogSnapshot = {
  revision: number;
  lastSyncedAt: string;
  products: Product[];
};

type SeedProduct = {
  sku: string;
  name: string;
  category: string;
  basePrice: number;
  baseInventory: number;
};

const seedProducts: SeedProduct[] = [
  { sku: 'SKU-1001', name: 'Aster Lamp', category: 'Lighting', basePrice: 74, baseInventory: 42 },
  { sku: 'SKU-1002', name: 'Orbit Desk', category: 'Furniture', basePrice: 219, baseInventory: 18 },
  { sku: 'SKU-1003', name: 'Cloud Chair', category: 'Furniture', basePrice: 189, baseInventory: 8 },
  { sku: 'SKU-1004', name: 'Northfield Shelf', category: 'Storage', basePrice: 129, baseInventory: 27 },
  { sku: 'SKU-1005', name: 'Signal Mug', category: 'Merchandising', basePrice: 16, baseInventory: 124 }
];

let upstreamRevision = 18;
let upstreamSyncedAt = new Date('2026-07-17T03:20:00.000Z');

function buildCatalogSnapshot(): CatalogSnapshot {
  const revisionOffset = upstreamRevision % 5;

  return {
    revision: upstreamRevision,
    lastSyncedAt: upstreamSyncedAt.toISOString(),
    products: seedProducts.map((product, index) => {
      const inventory = Math.max(0, product.baseInventory - (revisionOffset + index) * 2);
      const price = Number((product.basePrice + revisionOffset * (index + 1) * 1.75).toFixed(2));
      const availability: Product['availability'] = inventory === 0 ? 'Backorder' : inventory < 15 ? 'Low stock' : 'In stock';

      return {
        sku: product.sku,
        name: product.name,
        category: product.category,
        price,
        inventory,
        availability
      };
    })
  };
}

async function getCatalogSnapshot() {
  'use cache';

  cacheTag('products');
  cacheLife('max');

  return buildCatalogSnapshot();
}

async function syncLatestCatalogSource() {
  upstreamRevision += 1;
  upstreamSyncedAt = new Date();
}

function formatUtcTimestamp(value: string) {
  return new Intl.DateTimeFormat('en-US', {
    dateStyle: 'medium',
    timeStyle: 'short',
    timeZone: 'UTC'
  }).format(new Date(value));
}

export default async function Page() {
  const catalog = await getCatalogSnapshot();

  async function syncLatestCatalog() {
    'use server';

    await syncLatestCatalogSource();
    revalidateTag('products', 'max');
  }

  const totalSkus = catalog.products.length;
  const lowStockSkus = catalog.products.filter((product) => product.availability !== 'In stock').length;
  const inventoryOnHand = catalog.products.reduce((sum, product) => sum + product.inventory, 0);

  return (
    <main className="page-shell">
      <section className="hero">
        <div>
          <p className="eyebrow">Admin catalog</p>
          <h1>Product catalog</h1>
          <p className="lede">
            Browse cached catalog data quickly, and trigger a background refresh when ERP or PIM data changes.
          </p>
        </div>

        <form action={syncLatestCatalog} className="sync-card">
          <div>
            <h2>Sync latest catalog</h2>
            <p>
              Marks the shared <code>products</code> cache stale so all product views refresh in the background.
            </p>
          </div>
          <button type="submit">Sync latest catalog</button>
        </form>
      </section>

      <section className="stats" aria-label="Catalog summary">
        <article>
          <span>Total SKUs</span>
          <strong>{totalSkus}</strong>
        </article>
        <article>
          <span>Low stock</span>
          <strong>{lowStockSkus}</strong>
        </article>
        <article>
          <span>Inventory on hand</span>
          <strong>{inventoryOnHand}</strong>
        </article>
        <article>
          <span>Catalog revision</span>
          <strong>{catalog.revision}</strong>
        </article>
      </section>

      <section className="panel">
        <div className="panel-header">
          <div>
            <h2>Current snapshot</h2>
            <p>Last upstream sync: {formatUtcTimestamp(catalog.lastSyncedAt)} UTC</p>
          </div>
          <p className="panel-note">Cached with `use cache` and tagged as `products`.</p>
        </div>

        <div className="table-wrap">
          <table>
            <thead>
              <tr>
                <th>SKU</th>
                <th>Product</th>
                <th>Category</th>
                <th className="numeric">Price</th>
                <th className="numeric">Inventory</th>
                <th>Status</th>
              </tr>
            </thead>
            <tbody>
              {catalog.products.map((product) => (
                <tr key={product.sku}>
                  <td>{product.sku}</td>
                  <td>{product.name}</td>
                  <td>{product.category}</td>
                  <td className="numeric">${product.price.toFixed(2)}</td>
                  <td className="numeric">{product.inventory}</td>
                  <td>
                    <span className={`badge ${product.availability.toLowerCase().replace(' ', '-')}`}>
                      {product.availability}
                    </span>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </section>

    </main>
  );
}

